import { useState } from "react";
import { api, getAuthToken } from "../api";
import MedicineCard from "../components/MedicineCard";

export default function Search() {
  const [query, setQuery] = useState("");
  const [meds, setMeds] = useState([]);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");

  const search = async () => {
    if (!getAuthToken()) {
      setError("Please login first.");
      setMeds([]);
      return;
    }

    try {
      setError("");
      setMessage("");
      const res = await api.get("/medicines/");
      const medicines = Array.isArray(res.data) ? res.data : (res.data.results || []);
      setMeds(
        medicines.filter((m) =>
          m.name.toLowerCase().includes(query.toLowerCase())
        )
      );
    } catch (err) {
      setError("Unable to fetch medicines. Please login and try again.");
      setMeds([]);
    }
  };

  const addToCart = async (medicineId) => {
    try {
      setError("");
      await api.post("/cart/", { medicine: medicineId, quantity: 1 });
      setMessage("Added to cart.");
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to add to cart.");
    }
  };

  return (
    <div className="page">
      <h2>Search Medicine</h2>
      <input placeholder="Search..." value={query} onChange={e => setQuery(e.target.value)} />
      <button onClick={search}>Search</button>
      {error && <p>{error}</p>}
      {message && <p>{message}</p>}

      {meds.map((m) => (
        <div key={m.id}>
          <MedicineCard medicine={m} />
          <button onClick={() => addToCart(m.id)}>Add to Cart</button>
        </div>
      ))}
    </div>
  );
}
